import{_ as t,a,b as s}from"./chunks/支持留言.NiGCLVdp.js";import{_ as i,o,c as l,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"ta/Other/blog.md","filePath":"ta/Other/blog.md","lastUpdated":1781962217000}'),n={name:"ta/Other/blog.md"};function r(c,e,d,g,h,u){return o(),l("div",null,[...e[0]||(e[0]=[p('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>Blog feature உங்கள் ImgBed site-க்கு தனி blog page சேர்க்கும்.</p><p>enable செய்த பிறகு visitors திறக்கலாம்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+t+'" alt="Blog homepage" loading="lazy"></p><p>இந்த blog open-source <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a> project-இல் இருந்து adapt செய்யப்பட்டது. ImgBed அதை rewrite செய்து Vue-உடன் integrate செய்கிறது, அதனால் image hosting site-இன் பகுதியாக இயங்கும்.</p><h2 id="எங்கு-configure-செய்வது" tabindex="-1">எங்கு Configure செய்வது <a class="header-anchor" href="#எங்கு-configure-செய்வது" aria-label="Permalink to &quot;எங்கு Configure செய்வது&quot;">​</a></h2><p>Blog settings:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+a+'" alt="Blog settings" loading="lazy"></p><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li><code>Enable</code> on செய்யவும்.</li><li>blog configuration சேமிக்க வேண்டிய GitHub account தேர்வு செய்யவும்.</li><li><code>Update Blog</code> கிளிக் செய்யவும்.</li><li>success message வர காத்திருக்கவும்.</li><li><code>https://your-domain.com/blog/</code> திறந்து blog பார்க்கவும்.</li></ol><p>முதல் பயன்படுத்தும்போது ImgBed selected account கீழ் private GitHub repository உருவாக்கும்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>இந்த repository blog settings மற்றும் article content சேமிக்கும்.</p><h2 id="posts-எழுதுவது" tabindex="-1">Posts எழுதுவது <a class="header-anchor" href="#posts-எழுதுவது" aria-label="Permalink to &quot;Posts எழுதுவது&quot;">​</a></h2><p>blog posts-ஐ உங்கள் private GitHub repository-ல் edit செய்யவும்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>சாதாரண workflow:</p><ol><li>GitHub திறக்கவும்.</li><li>private <code>imgbed-blog-config</code> repository-க்கு செல்லவும்.</li><li>post files edit அல்லது add செய்யவும்.</li><li>changes commit செய்யவும்.</li><li>ImgBed admin panel-க்கு திரும்பி <code>Update Blog</code> கிளிக் செய்யவும், அல்லது blog homepage மேல் இடது logo-ஐ மூன்று முறை click செய்து blog update trigger செய்யவும்.</li></ol><p><code>Update Blog</code> நீங்கள் எழுதிய content-ஐ overwrite செய்யாது. தேவைப்பட்டால் repository initialize செய்து blog cache refresh செய்யும்.</p><h2 id="supported-features" tabindex="-1">Supported Features <a class="header-anchor" href="#supported-features" aria-label="Permalink to &quot;Supported Features&quot;">​</a></h2><p>Blog post lists, categories, tags, archives, search, dark mode, language switching போன்ற பொதுவான blog features support செய்கிறது.</p><p>comments மற்றும் visit statistics-யும் support செய்கிறது.</p><p><img src="'+s+'" alt="Blog comments" loading="lazy"></p><p>comments posts கீழே தெரியும். visitors avatar, nickname, email, comment content submit செய்யலாம்.</p><p>visit statistics post views மற்றும் site visits காட்டும்; blog traffic புரிய உதவும்.</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Blog எப்போதும் <code>/blog/</code> கீழ் serve ஆகும்.</p><p>உங்கள் ImgBed domain:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>blog URL:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>blog disabled ஆன பிறகு visitors blog page access செய்ய முடியாது.</p>',34)])])}const f=i(n,[["render",r]]);export{v as __pageData,f as default};
